import java.security.MessageDigest;
import javax.crypto.Cipher;
import javax.crypto.spec.SecretKeySpec;
import org.json.JSONObject;

public class AESUtil {
    private static final String ENCRYPTION_KEY = "secret_key";
    private static final int ITERATIONS = 1024;
    private static final int KEY_SIZE = 128;

    public static byte[] encrypt(JSONObject object) {
        try {
            // generate encryption key from constant string
            SecretKeySpec secretKey = new SecretKeySpec(ENCRYPTION_KEY.getBytes(), "AES");
            Cipher cipher = Cipher.getInstance("AES/ECB/PKCS5Padding");
            cipher.init(Cipher.ENCRYPT_MODE, secretKey);

            // encrypt user data using AES encryption
            byte[] encryptedData = cipher.doFinal(object.toString().getBytes());
            return encryptedData;
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

    public static JSONObject decrypt(byte[] data) {
        try {
            // generate encryption key from constant string
            SecretKeySpec secretKey = new SecretKeySpec(ENCRYPTION_KEY.getBytes(), "AES");
            Cipher cipher = Cipher.getInstance("AES/ECB/PKCS5Padding");
            cipher.init(Cipher.DECRYPT_MODE, secretKey);

            // decrypt user data using AES encryption
            byte[] decryptedData = cipher.doFinal(data);
            JSONObject object = new JSONObject(new String(decryptedData));
            return object;
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }
}